function bgImgC = fReadBgV01(imgPathC,camClb,nmbCmr)% Return cell of backgrounud images for Bella magspec%% bgImgC = fBellaBgV01(imgDirC)%% bgImgC: cell of background image%% imgPathC: cell of image path% camClb: structure of calibration for bella magspec cameras%   .fov: field of view [mm]%   .yOffset: y offset for roi [pixel]%   .height: height of image [pixel]%   .xOffset: x offset for roi [pixel]%   .width: width of image [pixel]%   .leftPos: left position of image [mm]%   .yCnter: y center pixel%   .ySt,yEd: y start and end for analysis ROI%   .xSt,xEd: x start and end for analysis ROI% nmbCmr: number of cameras%%% Written by Kei Nakamura% 2013/4/26 ver.1: created%%% main bodyfor i=1:nmbCmr    imgPath = [imgPathC{i},'-001.png'];    [img,~] = f12bitPngOpnV04(imgPath);    bgImgC{i} = img(camClb(i).ySt:camClb(i).yEd,camClb(i).xSt:camClb(i).xEd);   % analysis roiend
